<?php
require_once __DIR__ . '/../includes/functions.php';
require_admin();
if($_SERVER['REQUEST_METHOD']==='POST'){ require_post_csrf(); try{ $action=$_POST['action'] ?? 'settings'; if($action==='settings'){ foreach(['site_name','site_email','site_phone','currency_symbol','low_stock_threshold','promo_title','promo_subtitle'] as $key){ $stmt=$pdo->prepare('INSERT INTO site_settings (setting_key, setting_value) VALUES (?, ?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)'); $stmt->execute([$key, trim($_POST[$key] ?? '')]); } set_flash('success','Settings saved.'); } elseif($action==='coupon_save'){ CouponService::save($_POST); set_flash('success','Coupon saved.'); } elseif($action==='coupon_delete'){ CouponService::delete((int)$_POST['id']); set_flash('success','Coupon deleted.'); } }catch(Throwable $e){ set_flash('danger',$e->getMessage()); } redirect('admin/settings.php'); }
$coupons=CouponService::all(); $pageTitle='Settings'; $activePage='settings'; require __DIR__.'/../includes/header.php';
?>
<main class="container-fluid admin-shell"><div class="row g-4"><aside class="col-lg-2"><?php require __DIR__.'/../includes/sidebar.php'; ?></aside><section class="col-lg-10"><h1 class="section-title mb-4">Settings & Coupons</h1><div class="row g-4"><div class="col-xl-5"><div class="card form-card"><div class="card-body"><h5>Site Settings</h5><form method="post"><?= csrf_input() ?><input type="hidden" name="action" value="settings"><?php foreach(['site_name'=>'Site Name','site_email'=>'Site Email','site_phone'=>'Site Phone','currency_symbol'=>'Currency Symbol','low_stock_threshold'=>'Low Stock Threshold','promo_title'=>'Promo Title','promo_subtitle'=>'Promo Subtitle'] as $key=>$label): ?><div class="mb-3"><label class="form-label"><?= e($label) ?></label><input name="<?= e($key) ?>" class="form-control" value="<?= e(setting($key,'')) ?>"></div><?php endforeach; ?><button class="btn btn-primary">Save Settings</button></form></div></div></div><div class="col-xl-7"><div class="card form-card mb-4"><div class="card-body"><h5>Add / Update Coupon</h5><form method="post" class="row g-2"><?= csrf_input() ?><input type="hidden" name="action" value="coupon_save"><div class="col-md-3"><input name="code" class="form-control" placeholder="CODE" required></div><div class="col-md-2"><select name="discount_type" class="form-select"><option value="fixed">Fixed</option><option value="percent">Percent</option></select></div><div class="col-md-2"><input type="number" step="0.01" name="discount_value" class="form-control" placeholder="Value" required></div><div class="col-md-2"><input type="number" step="0.01" name="minimum_order" class="form-control" placeholder="Min"></div><div class="col-md-3"><input type="date" name="expires_at" class="form-control"></div><div class="col-md-3"><input type="number" name="usage_limit" class="form-control" placeholder="Usage limit"></div><div class="col-md-3"><select name="status" class="form-select"><option value="active">Active</option><option value="inactive">Inactive</option></select></div><div class="col-md-3"><button class="btn btn-primary w-100">Save Coupon</button></div></form></div></div><div class="card table-card"><div class="table-responsive"><table class="table mb-0 align-middle"><thead class="table-light"><tr><th>Code</th><th>Type</th><th>Value</th><th>Min</th><th>Used</th><th>Expiry</th><th></th></tr></thead><tbody><?php foreach($coupons as $c): ?><tr><td><?= e($c['code']) ?></td><td><?= e($c['discount_type']) ?></td><td><?= e($c['discount_value']) ?></td><td><?= money($c['minimum_order']) ?></td><td><?= (int)$c['used_count'] ?>/<?= e($c['usage_limit'] ?? '∞') ?></td><td><?= e($c['expires_at'] ?? '-') ?></td><td><form method="post" class="confirm-form no-loader"><?= csrf_input() ?><input type="hidden" name="action" value="coupon_delete"><input type="hidden" name="id" value="<?= (int)$c['id'] ?>"><button class="btn btn-sm btn-outline-danger">Delete</button></form></td></tr><?php endforeach; ?></tbody></table></div></div></div></div></section></div></main>
